import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"关于基亚纳谷地叛民的处理","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/192-关于基亚纳谷地叛民的处理.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/192-关于基亚纳谷地叛民的处理.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/192-关于基亚纳谷地叛民的处理.md"};function o(s,a,n,_,m,d){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"关于基亚纳谷地叛民的处理",tabindex:"-1"},[t("关于基亚纳谷地叛民的处理 "),e("a",{class:"header-anchor",href:"#关于基亚纳谷地叛民的处理","aria-label":'Permalink to "关于基亚纳谷地叛民的处理"'},"​")],-1),e("p",null,"关于基亚纳谷地叛民的处理方式 没有采取上述两种措施中的任何一种。人们不能声称阿雷佐人每天都被赶 到佛罗伦萨、政府被废黜、财产被抄没、公然被羞辱、家园被占领算是得 到了恩惠。然而，也不能说保留其城墙毫发无伤、允许其5/6的公民继续 生活在那里却不派新居民去制衡他们就是在保卫我们自己。在未来我们可 能不得不面临的任何战争中，我们被迫花在阿雷佐的开销将比对付任何其 他敌人都要多。早在阿雷佐反叛或我们开始酷烈报复之前，1498年的经历 就已教给了我们这一点。当威尼斯的军队袭击比别纳⑨时，我们只能往阿 雷佐派去米兰公爵的军队和里努奇奥伯爵及其下属一起确保城市的安定， 而不是派他们去卡森蒂诺抗击敌人；要不然我们也不必从比萨防线调回保 罗 ·维泰利和他的人去卡森蒂诺与威尼斯人作战。如果阿雷佐保持忠诚， 我们便不必为其谋逆承担巨大风险和开支。因此，综合今昔人们所见证的 以及我们强加给阿雷佐人的条件，人们必然会得出结论：如果——但愿不 要!——我们遭遇入侵，阿雷佐要么反叛要么在我们全力保住它时给我们 招来大量麻烦，它将成为佛罗伦萨的一块烫手山芋。 我不想忽视佛罗伦萨被侵犯的可能以及任何入侵者都必然会打阿雷佐 的主意，这是当下议论的一个中心议题。让我们先不去管阿尔卑斯山外君 主们②可能的威胁，先来看看我们迫在眉睫的危险。任何见识过公爵(切 萨雷 ·博尔贾)做派的人都会注意到他在维护自己已占领的土地时所采取 的策略，他从来不指望意大利的盟友，对威尼斯不屑一顾，佛罗伦萨在他 眼中更是等而下之。人们只能猜测他是想在意大利创建一个相当强大的政 权以使自己牢不可破，足以令任何统治者与之结盟都有利可图。倘若这就 是他的如意盘算，那么他显然正迫切希望拿下托斯卡纳全境从而与周边他 已征服的国家③连成一个更强大的王国。基于我刚刚提出的理由和他无穷 的野心，以及他与我们旷日持久地谈判却无意达成任何协议的做法，无疑",-1),e("p",null,"①1502年发生的反对佛罗伦萨占领的叛乱。 ——英译者注 ②法国国王、西班牙国王和神圣罗马帝国皇帝。 ——国家版注 ③罗马涅和乌尔比诺。 ——英译者注",-1),e("p",null,"马基雅维利全集 Opere complete di Niccolò Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
